// GET /api/posts?limit=20&after=<cursor>

// --- Cursor helpers --------------------------------------------------------

// Encode the (created_at, id) tuple of the last row into an opaque token.
function encodeCursor(row) {
    const payload = JSON.stringify({
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    });
    return Buffer.from(payload, 'utf8').toString('base64url');
}

// Decode + validate. Throws on anything malformed so the caller can return 400.
function decodeCursor(cursor) {
    let decoded;
    try {
        decoded = Buffer.from(cursor, 'base64url').toString('utf8');
    } catch {
        throw new Error('Invalid cursor encoding');
    }

    let parsed;
    try {
        parsed = JSON.parse(decoded);
    } catch {
        throw new Error('Invalid cursor payload');
    }

    if (
        !parsed ||
        typeof parsed !== 'object' ||
        typeof parsed.created_at !== 'string' ||
        !Number.isInteger(parsed.id) ||
        Number.isNaN(Date.parse(parsed.created_at))
    ) {
        throw new Error('Invalid cursor fields');
    }

    return { created_at: parsed.created_at, id: parsed.id };
}

// --- Endpoint --------------------------------------------------------------

async function getPosts(req, res) {
    // Clamp limit to a sane range to protect the DB.
    let limit = parseInt(req.query.limit, 10) || 20;
    limit = Math.min(Math.max(limit, 1), 100);

    // Decode the cursor up front so a bad token fails fast with a 400.
    let cursor = null;
    if (req.query.after !== undefined) {
        try {
            cursor = decodeCursor(req.query.after);
        } catch {
            return res.status(400).json({ error: 'Invalid pagination cursor' });
        }
    }

    // LIMIT N+1 trick: fetch one extra row to detect whether more pages exist.
    const fetchLimit = limit + 1;

    let result;
    if (cursor) {
        // Compound (created_at, id) keyset comparison matching the
        // ORDER BY created_at DESC, id DESC sort.
        //
        // We want rows that come *after* the cursor in the sort order, i.e.
        // strictly "less than" (created_at, id) since the order is DESC.
        // The row tuple comparison expresses exactly that:
        //   (created_at, id) < (cursorCreatedAt, cursorId)
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (created_at, id) < ($1, $2)
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursor.created_at, cursor.id, fetchLimit]
        );
    } else {
        // First page — no cursor filter.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [fetchLimit]
        );
    }

    const rows = result.rows;
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor =
        hasMore && posts.length > 0
            ? encodeCursor(posts[posts.length - 1])
            : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}
```

### Notes on the implementation

- **Row-value comparison `(created_at, id) < ($1, $2)`** is the cleanest way to express a compound keyset. PostgreSQL evaluates it lexicographically: it matches rows where `created_at` is older, *or* `created_at` is equal and `id` is smaller — exactly the "next in `DESC, DESC` order" semantics. It also pairs well with a composite index `(created_at DESC, id DESC) WHERE published = true`, which makes each page an index range scan.
- **`base64url`** avoids `+`, `/`, and `=` that would otherwise need URL-encoding in the query string. (Plain `base64` also works if your Node version is older, but you'd want to URL-encode it.)
- **Validation in `decodeCursor`** checks the shape (`created_at` parseable date string, integer `id`) so a tampered or truncated token produces a 400 rather than a malformed SQL parameter or a silent wrong result.
- **`nextCursor` is `null`** on the last page, giving clients a clear stop signal.

### Why cursor-based pagination is superior here

1. **Constant performance at any depth.** `OFFSET 100000` forces PostgreSQL to read and discard 100,000 rows before returning the page — cost grows linearly with page depth. A keyset `WHERE (created_at, id) < (...)` jumps straight to the position via the index, so page 1 and page 10,000 cost the same.
2. **Stable results under writes.** With offsets, a row inserted or deleted near the top shifts everything down, causing rows to be **skipped or shown twice** as users page. A cursor anchors to a specific row's sort key, so concurrent inserts/deletes don't corrupt the sequence — important for a feed sorted by `created_at DESC`.
3. **No expensive COUNT.** `SELECT COUNT(*)` over a large table scans many rows on every request just to compute `totalPages`. Cursor pagination doesn't need a total, so it's dropped — and infinite-scroll/"load more" UIs rarely need a total count anyway.

**Trade-off:** clients can no longer jump to an arbitrary page number (`?page=57`); navigation is forward (and optionally backward, via a symmetric `before` cursor) only. For a chronological feed that's the right model.

