// ─── Cursor Helpers ───────────────────────────────────────────────────────────

/**
 * Encodes a (created_at, id) pair into an opaque base64 cursor string.
 * @param {Date|string} createdAt - The created_at timestamp of the last returned row.
 * @param {number|string} id - The id of the last returned row.
 * @returns {string} Base64-encoded cursor.
 */
function encodeCursor(createdAt, id) {
    const payload = JSON.stringify({
        created_at: createdAt instanceof Date ? createdAt.toISOString() : createdAt,
        id,
    });
    return Buffer.from(payload, 'utf8').toString('base64');
}

/**
 * Decodes a base64 cursor string back into { created_at, id }.
 * Returns null if the cursor is missing, malformed, or has invalid field types.
 * @param {string} cursor - The raw cursor string from the query parameter.
 * @returns {{ created_at: string, id: number|string } | null}
 */
function decodeCursor(cursor) {
    try {
        const json = Buffer.from(cursor, 'base64').toString('utf8');
        const parsed = JSON.parse(json);

        // Structural validation
        if (typeof parsed !== 'object' || parsed === null) return null;
        if (parsed.created_at == null || parsed.id == null) return null;

        // Semantic validation: created_at must be a parseable date
        if (isNaN(new Date(parsed.created_at).getTime())) return null;

        return { created_at: parsed.created_at, id: parsed.id };
    } catch {
        // Catches Buffer decode failures, JSON.parse failures, etc.
        return null;
    }
}

// ─── Endpoint ─────────────────────────────────────────────────────────────────

// GET /api/posts?limit=20&after=<cursor>
async function getPosts(req, res) {
    // Parse & clamp limit. Never expose unbounded queries to the caller.
    const limit = Math.min(Math.max(parseInt(req.query.limit) || 20, 1), 100);
    const afterParam = req.query.after;

    // ── Decode cursor (if provided) ──────────────────────────────────────────
    let cursor = null;
    if (afterParam !== undefined) {
        cursor = decodeCursor(afterParam);
        if (!cursor) {
            return res.status(400).json({
                error: 'Invalid cursor. The `after` parameter is malformed or expired.',
            });
        }
    }

    // ── Build & run query ────────────────────────────────────────────────────
    //
    // LIMIT N+1 trick: fetch one extra row to determine whether a next page
    // exists without issuing a separate COUNT(*) query.
    //
    // Compound row-value comparison (created_at, id) < ($1, $2) expands to:
    //   created_at < $1  OR  (created_at = $1 AND id < $2)
    // which correctly follows the ORDER BY created_at DESC, id DESC sort.

    let result;

    if (cursor) {
        // Subsequent pages: resume after the cursor position.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (created_at, id) < ($1::timestamptz, $2)
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursor.created_at, cursor.id, limit + 1]
        );
    } else {
        // First page: no cursor filter.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [limit + 1]
        );
    }

    // ── Apply N+1 trick ──────────────────────────────────────────────────────
    const rows = result.rows;
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows; // trim the extra row

    // ── Build next cursor from the last row actually returned ────────────────
    let nextCursor = null;
    if (hasMore) {
        const last = posts[posts.length - 1];
        nextCursor = encodeCursor(last.created_at, last.id);
    }

    return res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,   // null when on the last page
            limit,
        },
    });
}
```

